schema CanonicalToolCall:    {name: str, args: dict}
schema CanonicalToolResult:  {ok: bool, value: any, error: optional[str]}

adapters = {
    "rest":  RestAdapter(),
    "grpc":  GrpcAdapter(),
    "mcp":   McpAdapter(),
    "cli":   CliAdapter(),
    "lib":   LibAdapter(),
}

function register_tool(name, ecosystem, schema, native_handle):
    tools.register(name, handler=adapters[ecosystem],
                   schema=schema, native=native_handle)

function dispatch(call: CanonicalToolCall) -> CanonicalToolResult:
    entry = tools.lookup(call.name)
    validate(call.args, entry.schema)

    # Per-ecosystem translation: canonical -> native -> result -> canonical.
    native_req  = entry.handler.to_native(call, entry.native)
    native_resp = entry.handler.invoke(native_req)
    return entry.handler.from_native(native_resp)

# Agent only ever sees the canonical interface.
function agent_step(messages):
    reply = llm.generate(messages=messages, tools=tools.descriptors())
    for call in reply.tool_calls:
        result = tools.dispatch(call.name, call.args)
        messages.append(tool_result(call.id, result))
    return reply

# Why this works: the agent's calling convention stays fixed while new
# ecosystems plug in as adapter instances; integration work is bounded
# to the translation seam instead of leaking into the agent loop.
# Related: see `crawler-dispatcher`, `hierarchical-tool-selection`.

# Production-grade adapter layer.
#   - JSON Schema validation on canonical inputs AND outputs
#   - circuit-breaker per adapter so a flaky REST tool stops being routed
#   - idempotency key on every side-effecting dispatch
#   - dry-run mode that skips invoke() but still runs translation

class AdapterRegistry:
    def __init__(self):
        self.tools     = {}
        self.breakers  = {}      # name -> CircuitBreaker
        self.audit     = AuditLog("adapter.audit.jsonl")

    def register(self, name, ecosystem, schema, native, side_effect=False):
        self.tools[name] = {
            "adapter":     ADAPTERS[ecosystem],
            "schema":      schema,
            "native":      native,
            "side_effect": side_effect,
        }
        self.breakers[name] = CircuitBreaker(threshold=5, cooldown="60s")

    def dispatch(self, call, dry_run=False, idem_key=None):
        entry = self.tools[call.name]
        validate(call.args, entry["schema"]["input"])     # reject early

        if entry["side_effect"]:
            require(idem_key, "idempotency key required")
            if self.audit.seen(idem_key):
                return self.audit.replay(idem_key)         # safe retry

        breaker = self.breakers[call.name]
        if breaker.open: return error("circuit_open", call.name)

        native_req = entry["adapter"].to_native(call, entry["native"])
        if dry_run:
            return ok({"dry_run": True, "native_req": native_req})

        try:
            native_resp = entry["adapter"].invoke(native_req)
            result      = entry["adapter"].from_native(native_resp)
            validate(result.value, entry["schema"]["output"])
            breaker.record_success()
        except NativeError as e:
            breaker.record_failure()
            result = error("native_failure", str(e))
        self.audit.record(call=call, idem=idem_key, result=result)
        return result

# Why this works: every canonical call is validated, audited, and
# replay-safe, so a misbehaving adapter is fenced off without leaking
# bad outputs into the agent loop or double-charging an idempotent op.
# Related: see `crawler-dispatcher`, `hierarchical-tool-selection`.

