# Production augmented-LLM block. Each augmentation (retrieve/tool/memory)
# is a registered handler with its own retry policy, breaker, and quota.

class AugmentedBlock:
    def __init__(self):
        self.tools    = ToolRegistry()
        self.breakers = {}
        self.audit    = AuditLog("augmented.audit.jsonl")
        self.quota    = WriteQuota(per_session=50)   # memory_write cap

    def register(self):
        self.tools.register("retrieve",     self._retrieve,
                             schema={"query": str})
        self.tools.register("call_tool",    self._call_tool,
                             schema={"name": str, "args": dict})
        self.tools.register("memory_read",  self._mem_read,
                             schema={"key": str})
        self.tools.register("memory_write", self._mem_write,
                             schema={"key": str, "value": any})
        for name in ["retrieve", "call_tool"]:
            self.breakers[name] = CircuitBreaker(threshold=4, cooldown="30s")

    def _retrieve(self, query):
        return retry_with_backoff(lambda: corpus.search(query),
                                    breaker=self.breakers["retrieve"])

    def _call_tool(self, name, args):
        return retry_with_backoff(lambda: external.invoke(name, args),
                                    breaker=self.breakers["call_tool"])

    def _mem_read(self, key):  return memory.get(key)
    def _mem_write(self, key, value):
        if not self.quota.allow(): return error("quota_exhausted")
        return memory.put(key, value)

    def step(self, messages):
        reply = llm.generate(messages=messages,
                              tools=self.tools.descriptors())
        messages.append(reply)
        for call in reply.tool_calls:
            result = self.tools.dispatch(call.name, call.args)
            self.audit.record(aug=call.name, args=call.args,
                               ok=result.ok, latency=result.latency)
            messages.append(tool_result(call.id, result))
        return reply

# Why this works: every augmentation goes through the same registry,
# so failure handling, quotas, and audit are uniform; a flaky retrieval
# stops being called and the memory layer cannot be silently flooded.
# Related: see `hierarchical-tool-selection`, `tool-result-caching`.

# Compose augmented-LLM with an action-selector: the model can PROPOSE
# retrieval, tool, and memory calls, but a deterministic selector decides
# which proposals execute. The selector enforces budget, scope, and
# precedence rules the model cannot override.

POLICY = {
    "retrieve":     {"max_per_step": 2, "max_per_session": 10},
    "call_tool":    {"max_per_step": 1, "requires_scope": True},
    "memory_read":  {"max_per_step": 4},
    "memory_write": {"max_per_step": 1, "requires_critic": True},
}

class ActionSelector:
    def __init__(self, policy, scope):
        self.policy = policy; self.scope = scope; self.counts = {}

    def select(self, proposals, critic_ok):
        chosen = []
        for p in proposals:
            rule = self.policy[p.name]
            if self.counts.get(p.name, 0) >= rule["max_per_step"]:
                continue
            if rule.get("requires_scope") and not in_scope(p, self.scope):
                continue
            if rule.get("requires_critic") and not critic_ok(p):
                continue
            self.counts[p.name] = self.counts.get(p.name, 0) + 1
            chosen.append(p)
        return chosen

function augmented_step(messages, selector, tools):
    reply = llm.generate(messages=messages, tools=tools.descriptors())
    messages.append(reply)
    if not reply.tool_calls:
        return reply

    approved = selector.select(
        proposals=reply.tool_calls,
        critic_ok=lambda p: critic.approve_write(p),
    )
    for call in approved:
        result = tools.dispatch(call.name, call.args)
        messages.append(tool_result(call.id, result))
    for skipped in set(reply.tool_calls) - set(approved):
        messages.append(tool_result(
            skipped.id, error("policy_denied", skipped.name)))
    return reply

# Why this works: the model still drives intent (it picks which
# augmentation it wants), but the selector enforces hard budgets and
# scope so an over-eager generation can never burn the session's tool
# quota or write to memory without a critic sign-off.
# Related: see `action-selector-pattern`, `hierarchical-tool-selection`.

