# Production dual-system loop:
#   low-confidence grounding -> replan (not act); sensitive actions
#   need dry-run + human approval; replan budget; correlated audit.

SENSITIVE = {"submit_payment", "delete", "send_message"}
GROUND_MIN, REPLAN_LIMIT = 0.75, 4

def run_dual_system(task, decision, grounding, screen):
    audit = AuditLog("dual.audit.jsonl")
    msgs, replans = [user(task)], 0

    for step in range(MAX_STEPS):
        shot = screen.capture()
        corr = new_correlation_id()
        intent = decision.next_intent(task=task, screenshot=shot,
                                       history=msgs)
        audit.record(corr=corr, op="intent", value=intent)
        if intent.name == "done":
            return intent.args.summary

        action, conf = grounding.ground(intent=intent, screenshot=shot)
        audit.record(corr=corr, op="ground", action=action, conf=conf)

        if conf < GROUND_MIN:
            replans += 1
            if replans > REPLAN_LIMIT: return abort("replan_limit")
            msgs.append(observation({"low_conf": conf})); continue

        if intent.name in SENSITIVE:
            if not human_approves(intent, screen.dry_run(action)):
                return abort("human_denied")

        try: screen.execute(action); ok = True
        except GroundingFailed as e:
            audit.record(corr=corr, op="exec_failed", err=str(e)); ok = False
        msgs.append(observation({"corr": corr, "ok": ok}))
    return abort("step_budget")

# Why this works: low-confidence grounding routes back to the planner
# instead of committing a wrong click, and the correlated audit makes
# postmortems attribute failures to the right model.
# Related: see `policy-localizer-validator`, `mobile-ui-agent`.

# Compose dual-system with structured-output: the decision model's
# intent is constrained to a typed JSON envelope drawn from a closed
# vocabulary, so the grounding model never has to parse free text.

INTENT_SCHEMA = {
    "type": "object",
    "required": ["name", "target", "args"],
    "properties": {
        "name":   {"enum": ["open", "tap", "swipe", "type",
                              "back", "home", "done"]},
        "target": {"type": "object",
                    "required": ["label"],
                    "properties": {
                        "label":   {"type": "string"},
                        "role":    {"type": "string"},   # "button", "link"
                        "region":  {"type": "string"},   # "top-right"
                    }},
        "args":   {"type": "object"},
    },
}

function run(task, screen, decision, grounding):
    msgs = [user(task)]
    for step in 1..MAX_STEPS:
        screenshot = screen.capture()

        intent = decision.next_intent(
            task=task, screenshot=screenshot, history=msgs,
            response_format=INTENT_SCHEMA,         # constrained generation
        )
        validate(intent, INTENT_SCHEMA)            # belt-and-braces

        if intent.name == "done":
            return intent.args.get("summary", "ok")

        # Grounding model receives a typed object, not prose.
        action = grounding.ground_typed(
            intent=intent, screenshot=screenshot,
        )
        screen.execute(action)
        msgs.append(observation({"intent": intent, "action": action}))
    return abort("step_budget")

