# Production MCP-as-code materialisation.
#   - schema fingerprint per tool; only regenerate wrappers that changed
#   - generated wrappers carry timeout and retry policy
#   - sandbox.execute() runs under CPU/memory/network caps
#   - every script run is audited with stdout/stderr hashes

WRAPPER_TPL = """
// AUTO-GENERATED: server={server}, tool={name}, fp={fp}
export async function {name}(args: {input_type}): Promise<{output_type}> {{
    validate(args, {input_schema});
    return mcp_call("{server}", "{name}", args,
                     {{ timeout_ms: 30000, retries: 2 }});
}}
"""

def materialise(mcp_servers, out_dir):
    audit = AuditLog("materialise.audit.jsonl")
    for server in mcp_servers:
        for tool in server.tools_list():
            fp = sha256_of(tool.input_schema, tool.output_schema)
            path = f"{out_dir}/servers/{server.name}/{tool.name}.ts"
            if existing_fp(path) == fp:
                continue                       # unchanged
            write(path, WRAPPER_TPL.format(
                server=server.name, name=tool.name, fp=fp,
                input_type=type_from(tool.input_schema),
                output_type=type_from(tool.output_schema),
                input_schema=json(tool.input_schema)))
            audit.record(server=server.name, tool=tool.name,
                          op="emit", fp=fp)

def agent_step(task, sandbox):
    script = llm.write_code(
        task=task,
        context=["see servers/ for typed wrappers; list/read on demand"])
    run = sandbox.execute(script,
                           cpu_ms=10000, mem_mb=512, net="mcp-only")
    audit_run(task=task.id,
               stdout_hash=sha256(run.stdout),
               exit=run.exit, duration_ms=run.duration_ms)
    if run.exit != 0:
        return error("script_failed", run.stderr)
    return run.value or run.stdout              # only output crosses back

# Why this works: large intermediate tool outputs stay inside the
# sandbox so they never burn context tokens, schema fingerprints make
# regeneration cheap, and resource caps fence runaway scripts.
# Related: see `sandbox-isolation`, `tool-search-lazy-loading`.

# Production MCP bridge — one registry, two sides, hardened.
#   inbound:  credential vault, schema validation, per-server breaker
#   outbound: per-peer auth, rate-limit, capability negotiation, audit

class MCPBridge:
    def __init__(self, registry, vault, policy):
        self.registry = registry; self.vault = vault; self.policy = policy
        self.breakers = {}
        self.audit    = AuditLog("bridge.audit.jsonl")

    def attach_clients(self):                       # inbound
        for name, transport in self.registry["client"].items():
            client = mcp.connect(transport, credentials=self.vault.get(name))
            client.initialize()
            self.breakers[name] = CircuitBreaker(5, "60s")
            for tool in client.tools_list():
                tools.register(f"{name}.{tool.name}",
                    lambda a, t=tool, n=name: self._call_ext(n, t, a),
                    schema=tool.input_schema)

    def _call_ext(self, server, tool, args):
        validate(args, tool.input_schema)
        if self.breakers[server].open: return error("breaker_open", server)
        try:
            r = mcp_clients[server].call(tool.name, args)
            self.breakers[server].record_success()
        except Exception as e:
            self.breakers[server].record_failure()
            r = error("external_failed", str(e))
        self.audit.record(dir="in", server=server, tool=tool.name); return r

    def serve(self, transport):                     # outbound
        srv = mcp.serve(transport=transport, on_initialize=self._negotiate)
        srv.on_call(self._handle); srv.run()

    def _negotiate(self, peer):
        ok = self.policy.capabilities_for(peer)
        return {k: filter_to(v, ok) for k, v in self.registry["server"].items()}

    def _handle(self, peer, kind, name, args):
        if not self.policy.allows(peer, kind, name):
            return error("forbidden", f"{kind}/{name}")
        ratelimit.acquire(peer)
        self.audit.record(dir="out", peer=peer, kind=kind, name=name)
        return dispatch_published(kind, name, args)

# Why this works: one registry+policy decides what flows either way,
# breakers fence flaky upstreams, per-peer rate limits keep eager
# consumers from drowning the published side.
# Related: see `mcp-as-code-api`, `tool-agent-registry`.

# Production mobile UI loop with guards on blast radius and loops.

MAX_ACTIONS = 60
SENSITIVE = {"buy", "purchase", "send", "delete", "confirm payment"}

class MobileAgent:
    def __init__(self, device, allowed_packages):
        self.device, self.allowed = device, set(allowed_packages)
        self.actions, self.noops = 0, 0
        self.audit = AuditLog("mobile.audit.jsonl")

    def run(self, task):
        msgs = [system_prompt, user(task)]
        for step in range(MAX_STEPS):
            if self.actions >= MAX_ACTIONS: return abort("action_budget")
            if self.device.foreground_package() not in self.allowed:
                return abort("foreign_app")

            before, ann = self.device.capture(), self.device.ui_dump()
            msgs.append(user_image_with(image=before, annotations=ann))
            reply = llm.generate(messages=msgs, tools=ACTION_VOCAB)
            call  = reply.tool_calls[0]
            if call.name == "done": return call.args.summary

            label = ann.label_at(call.args.get("x"), call.args.get("y"))
            if label and label.lower() in SENSITIVE and not human_confirms(call):
                return abort("human_denied")

            self.device.execute(call.name, call.args); self.actions += 1
            after = self.device.capture()
            diff  = image_diff(before, after)
            self.audit.record(action=call, label=label, diff=diff)
            if diff < 0.01:
                self.noops += 1
                if self.noops >= 3: return abort("stuck")
                msgs.append(observation("no_visible_change"))
            else:
                self.noops = 0
        return abort("step_budget")

# Why this works: the no-op detector breaks the agent out of tap-the-wrong-spot
# loops, the foreign-app guard contains blast radius, and the sensitive-label
# confirmation prevents an accidental purchase.
# Related: see `dual-system-gui-agent`, `app-exploration-phase`.

function run_voice_session(audio_in_stream):
    stt = open_streaming_stt(languages=TARGET_LANGS)
    llm = open_streaming_llm(multilingual=true)
    tts_pool = {lang: open_streaming_tts(lang) for lang in TARGET_LANGS}

    history = []
    for audio_chunk in audio_in_stream:
        partial = stt.feed(audio_chunk)
        if not partial.is_final:
            continue

        # language + dialect carried as structured metadata, not lost
        lang, dialect = partial.lang, partial.dialect
        history.append(user(partial.text, lang=lang, dialect=dialect))

        for text_chunk in llm.stream(history, target_lang=lang):
            audio = tts_pool[lang].stream(text_chunk, dialect=dialect)
            yield audio          # sub-second turn-taking
        history.append(assistant(llm.last_message, lang=lang))

function run(task, screen):
    history = [user(task)]

    for step in 1..MAX_STEPS:
        screenshot = screen.capture()

        # 1. Policy — largest model, plans next textual action
        textual_action = policy_llm.next(
            task=task, screenshot=screenshot, history=history,
        )                       # e.g. "click the Sign In button in the top-right"
        if textual_action == "DONE":
            return summarise(history)

        # 2. Localizer — small specialist VLM, grounds text to coordinates
        coords = localizer_vlm.locate(
            description=textual_action,
            screenshot=screenshot,
        )                       # e.g. (918, 124)
        screen.tap(coords)
        after = screen.capture()

        # 3. Validator — mid-sized VLM trained on completion judgements
        verdict = validator_vlm.judge(
            task=task, before=screenshot, after=after,
        )                       # {label: complete|incomplete|failed, conf: 0.92}
        if verdict.label == "complete" and verdict.conf >= 0.8:
            return summarise(history)
        if verdict.label == "failed" and verdict.conf >= 0.8:
            history.append(observation("grounding failed; replanning"))
            continue
        history.append(observation({"action": textual_action, "after": after}))

    return abort("step budget exhausted")

# Production Policy-Localizer-Validator with per-model breakers and
# a validator gate that decides commit vs replan vs fail.

MODELS   = {"policy": client("p"), "loc": client("l"), "val": client("v")}
BREAKERS = {k: CircuitBreaker(8, "120s") for k in MODELS}
AUDIT    = AuditLog("plv.audit.jsonl")
SENSITIVE = {"submit", "purchase", "delete", "send"}

def _call(model_name, fn, *a):
    if BREAKERS[model_name].open: raise CircuitOpen(model_name)
    try: r = fn(*a); BREAKERS[model_name].record_success(); return r
    except Exception as e: BREAKERS[model_name].record_failure(); raise

def run_plv(task, screen):
    history = [user(task)]
    for step in range(MAX_STEPS):
        shot, corr = screen.capture(), new_correlation_id()
        intent = _call("policy", MODELS["policy"].next, task, shot, history)
        AUDIT.record(corr=corr, op="intent", value=intent)
        if intent == "DONE": return summarise(history)

        coords, gconf = _call("loc", MODELS["loc"].locate, intent, shot)
        AUDIT.record(corr=corr, op="ground", coords=coords, conf=gconf)
        if gconf < 0.7:
            history.append(observation("low_ground_conf")); continue

        if any(s in intent.lower() for s in SENSITIVE) \
                and not human_approves(intent, coords, shot):
            return abort("human_denied")

        screen.tap(coords); after = screen.capture()
        verdict = _call("val", MODELS["val"].judge, task, shot, after)
        AUDIT.record(corr=corr, op="validate", verdict=verdict)

        if verdict.label == "complete" and verdict.conf >= 0.85:
            return summarise(history)
        if verdict.label == "failed" and verdict.conf >= 0.85:
            history.append(observation("validator_failed; replanning")); continue
        history.append(observation({"corr": corr}))
    return abort("step_budget")

# Why this works: the validator is an independent commit gate so the
# loop terminates on a verdict (not on whatever the planner last said),
# and per-model breakers contain regressions to one stage.
# Related: see `dual-system-gui-agent`, `mobile-ui-agent`.

# Compose PLV with structured-output: each boundary between models
# carries a typed envelope, validated on both sides, so a Policy that
# emits an unparseable intent or a Validator that returns ambiguous
# prose cannot poison the next stage.

INTENT_SCHEMA = {
    "required": ["description", "role", "region"],
    "properties": {
        "description": {"type": "string"},
        "role":        {"enum": ["button", "link", "input", "icon", "text"]},
        "region":      {"enum": ["top", "bottom", "left", "right", "center"]},
        "terminal":    {"type": "boolean"},
    }}
COORDS_SCHEMA = {
    "required": ["x", "y", "confidence"],
    "properties": {"x": {"type": "integer"},
                    "y": {"type": "integer"},
                    "confidence": {"type": "number"}}}
VERDICT_SCHEMA = {
    "required": ["label", "confidence", "reason"],
    "properties": {"label":     {"enum": ["complete", "incomplete", "failed"]},
                    "confidence": {"type": "number"},
                    "reason":     {"type": "string"}}}

function run(task, screen):
    history = [user(task)]

    for step in 1..MAX_STEPS:
        shot = screen.capture()

        intent = MODELS["policy"].next_typed(
            task, shot, history, response_format=INTENT_SCHEMA)
        validate(intent, INTENT_SCHEMA)
        if intent.get("terminal"): return summarise(history)

        coords = MODELS["localizer"].locate_typed(
            intent, shot, response_format=COORDS_SCHEMA)
        validate(coords, COORDS_SCHEMA)
        if coords.confidence < 0.7:
            history.append(observation("low_ground_conf")); continue

        screen.tap(coords); after = screen.capture()

        verdict = MODELS["validator"].judge_typed(
            task, shot, after, response_format=VERDICT_SCHEMA)
        validate(verdict, VERDICT_SCHEMA)

        if verdict.label == "complete" and verdict.confidence >= 0.85:
            return summarise(history)
        history.append(observation({"intent": intent,
                                      "coords": coords,
                                      "verdict": verdict}))
    return abort("step_budget")

# Why this works: typed envelopes at each boundary make stage failures
# attributable ("Localizer returned confidence 0.4"), so postmortems
