MOUNTS = {
    "/slack":  {"connector": slack_connector,  "rps": 10, "mode": "ro"},
    "/notion": {"connector": notion_connector, "rps": 5,  "mode": "ro"},
    "/github": {"connector": github_connector, "rps": 20, "mode": "ro"},
}

PATH_SCHEMA = {"type": "string", "pattern": "^/[A-Za-z0-9_./-]+$",
                "maxLength": 1024}

def _invoke(mount_key, op, **kwargs):
    mount = MOUNTS[mount_key]
    if circuit.tripped(mount_key):
        return {"error": "connector_unavailable", "mount": mount_key}
    if not rate_limit.allow(mount_key, mount["rps"]):
        return {"error": "rate_limited", "mount": mount_key}
    try:
        result = retry(lambda: getattr(mount["connector"], op)(**kwargs),
                       attempts=3, backoff="expo")
        circuit.record_success(mount_key)
        return result
    except ConnectorError as e:
        circuit.record_failure(mount_key)
        return {"error": str(e), "mount": mount_key}

def fs_handler(args, principal):
    schema.validate(args["path"], schema=PATH_SCHEMA)
    mount_key, sub = resolve(args["path"], MOUNTS)
    audit.log(principal=principal.id, op=args["op"], path=args["path"])
    return _invoke(mount_key, args["op"], sub=sub, **args.get("extra", {}))

def register_fs_tools():
    for op in ["list", "find", "cat", "search", "locate_in_tree"]:
        tools.register(f"fs.{op}", fs_handler,
                       schema={"path": PATH_SCHEMA, "op": {"const": op}},
                       side_effects="none")

def agent_step(messages, principal):
    reply = llm.generate(messages=messages, tools=tools.descriptors())
    for call in reply.tool_calls:
        messages.append(tool_result(call.id,
                                     tools.dispatch(call.name, call.args, principal)))
    return reply

# Why this works: the model still sees five clean primitives, but
# every call is rate-limited per mount, circuit-broken on upstream
# failure, and audited per principal so cross-source navigation is
# auditable and bounded.
# Related: see `agent-computer-interface`, `mcp`.

registry = {}      # keyed by entry id

function register(kind, entry):
    assert kind in {"tool", "agent"}
    registry[entry.id] = {
        "kind": kind,
        "description": entry.description,
        "capabilities": entry.capabilities,
        "cost_per_call": entry.cost,
        "p50_latency_ms": entry.latency,
        "quality_score": entry.quality,
        "handle": entry.handle,        # callable or A2A endpoint
    }

function query(task):
    candidates = [
        e for e in registry.values()
        if matches(e["description"], task) or matches(e["capabilities"], task)
    ]
    return rank(candidates, by=["quality_score", "-cost_per_call", "-p50_latency_ms"])

function dispatch(task):
    ranked = query(task)
    if not ranked: return abort("no capable tool or agent found")
    chosen = ranked[0]
    return chosen["handle"](task)      # call tool or invoke agent uniformly

# Production registry: advertised metadata is signed; observed metrics
# override the advertised numbers for ranking; per-principal allowlists
# enforce capability scope at dispatch. The registry's own surface is
# exposed through the tool dispatcher so agents query it uniformly.

REGISTRY = {}
OBSERVED = {}     # entry_id -> {p50_ms, success_rate, last_health_ok}

def registry_register_handler(args):
    kind, entry = args["kind"], args["entry"]
    assert kind in {"tool", "agent"}
    if not verify_signature(entry.metadata, entry.signature, AUTHORS):
        raise UnsignedEntry(entry.id)
    schema.validate(entry.metadata, schema=ENTRY_SCHEMA)
    REGISTRY[entry.id] = {"kind": kind, "meta": entry.metadata,
                          "handle": entry.handle}
    OBSERVED[entry.id] = {"p50_ms": entry.metadata["p50_latency_ms"],
                          "success_rate": 1.0, "last_health_ok": now()}

def registry_dispatch_handler(args, principal):
    task = args["task"]
    cands = [(eid, e) for eid, e in REGISTRY.items()
             if principal.allows(e["meta"]["capabilities"])
             and not circuit.tripped(eid)
             and now() - OBSERVED[eid]["last_health_ok"] <= 60_000
             and matches(e["meta"]["description"], task)]
    ranked = sorted(cands, key=lambda kv: (-OBSERVED[kv[0]]["success_rate"],
                                            OBSERVED[kv[0]]["p50_ms"]))
    if not ranked: return abort("no capable entry")
    eid, e = ranked[0]
    audit.log(principal=principal.id, entry=eid, task=task.id)
    try:
        t0 = now(); result = e["handle"](task)
        OBSERVED[eid]["p50_ms"] = ewma(OBSERVED[eid]["p50_ms"], now() - t0)
        circuit.record_success(eid); return result
    except Exception:
        circuit.record_failure(eid); raise

def bootstrap():
    tools.register("registry.register", registry_register_handler,
                   schema={"kind": "string", "entry": "object"})
    tools.register("registry.dispatch", registry_dispatch_handler,
                   schema={"task": "object"})

