        return PALETTE                            # cache hit

    advertised = registry.list_tools()            # MCP, internal dir, etc.
    PALETTE = {}
    for t in advertised:
        if not schema_valid(t.input_schema):
            log_warn("skipping malformed tool", t.name)
            continue
        PALETTE[t.name] = {
            "description": t.description,
            "input_schema": t.input_schema,
            "invoke": t.invoke,
        }
    LAST_REFRESH = now()
    return PALETTE

