# Production discovery: registries are remote, sometimes flaky, and
# sometimes lie. We sign-verify, schema-validate, cache with SWR, and
# circuit-break per endpoint. Every refresh logs adds/removes.

PALETTE = {}
LAST_OK = 0
TTL     = 300

def discover(registries):
    global PALETTE, LAST_OK
    if now() - LAST_OK < TTL and PALETTE:
        return PALETTE                                 # fresh cache

    next_palette = {}
    for reg in registries:
        if circuit.tripped(reg.id):
            metrics.inc("discovery.circuit_open", tags={"reg": reg.id})
            continue
        try:
            raw = retry(lambda: reg.list_tools(),
                        attempts=3, backoff="expo", max_ms=2000)
            if not verify_signature(raw, reg.public_key):
                metrics.inc("discovery.bad_signature", tags={"reg": reg.id})
                continue
            for t in raw.tools:
                if not schema.validate(t, schema=TOOL_SPEC_V2,
                                        soft=True):
                    metrics.inc("discovery.bad_schema", tags={"tool": t.name})
                    continue
                next_palette[t.name] = {"description": t.description,
                                        "input_schema": t.input_schema,
                                        "invoke": t.invoke,
                                        "source": reg.id}
            circuit.record_success(reg.id)
        except Exception:
            circuit.record_failure(reg.id)

    added   = set(next_palette) - set(PALETTE)
    removed = set(PALETTE) - set(next_palette)
    if added or removed:
        audit.log(op="discovery_refresh", added=list(added),
                  removed=list(removed))
    if next_palette:
        PALETTE, LAST_OK = next_palette, now()         # SWR: keep old on empty
    for name, spec in PALETTE.items():
        tools.register(name, spec["invoke"], schema=spec["input_schema"])
    return PALETTE

# Why this works: a discovery loop that does not validate signatures or
# schemas is a supply-chain risk; failing each tool individually rather
# than the whole refresh keeps the agent usable when one registry lies.
# Related: see `tool-loadout`, `tool-agent-registry`.

function run(user_message):
    messages = [system_prompt, user(user_message)]
    tools = registry.list()              # typed JSON-Schema palette

    for step in 1..MAX_STEPS:
        reply = llm.generate(messages=messages, tools=tools)
        messages.append(reply)

        if not reply.tool_calls:
            return reply.content         # model answered

        for call in reply.tool_calls:
            if not registry.validate(call.name, call.args):
                messages.append(tool_error(call.id, "schema invalid"))
                continue
            result = registry.execute(call.name, call.args)
            messages.append(tool_result(call.id, result))
        # next iteration: model sees results and decides next move

    return abort("step budget exhausted")

