FEASIBILITY_THRESHOLD = 0.6

def affordance_gate(candidates, scene_image):
    feasible = []
    for action in candidates:
        # pure perception: ask the VLM whether THIS body can do THIS action HERE
        result = vlm.score_affordance(
            image=scene_image,
            question=f"Can the robot {action.verb} the {action.target} "
                     f"in this scene? Is it reachable and {action.requirement}?",
        )
        # result has a score and, optionally, the grounded location
        if result.score >= FEASIBILITY_THRESHOLD:
            action.grounded_at = result.location
            feasible.append(action)
        else:
            log_filtered(action, result.reason)   # no real step spent
    return feasible

def step(goal, scene_image):
    candidates = planner.propose(goal, scene_image)
    feasible = affordance_gate(candidates, scene_image)
    if not feasible:
        return planner.revise(goal, scene_image, hint="all candidates infeasible")
    # the gate screens feasibility, NOT downstream effects -- no rollout, no simulator
    return controller.execute(feasible[0])

